package com.example.demo.services;import com.example.demo.dto.EmpleadoDTO;import com.example.demo.models.*;import com.example.demo.repository.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.util.*;
@Service public class EmpleadoService{private final PersonaRepository personas;private final PerfilEmpleadoRepository perfiles;private final PermisoUsuarioRepository permisos;private final AuditoriaService auditoria;public EmpleadoService(PersonaRepository personas,PerfilEmpleadoRepository perfiles,PermisoUsuarioRepository permisos,AuditoriaService auditoria){this.personas=personas;this.perfiles=perfiles;this.permisos=permisos;this.auditoria=auditoria;}@Transactional(readOnly=true)public List<EmpleadoDTO> listar(){return personas.findAll().stream().map(this::dto).toList();}@Transactional public EmpleadoDTO guardar(EmpleadoDTO d,Long operadorId){Persona p=personas.findById(d.usuarioId()).orElseThrow(()->new IllegalArgumentException("Usuario inexistente"));PerfilEmpleado e=perfiles.findByPersonaId(p.getId()).orElseGet(()->PerfilEmpleado.builder().persona(p).build());e.setLegajo(clean(d.legajo()));e.setPuesto(clean(d.puesto()));e.setFechaContratacion(d.fechaContratacion());e.setSueldo(d.sueldo());e.setTelefonoEmergencia(clean(d.telefonoEmergencia()));e.setObservaciones(clean(d.observaciones()));perfiles.save(e);permisos.deleteByPersonaId(p.getId());if(d.permisos()!=null)d.permisos().forEach(code->permisos.save(PermisoUsuario.builder().persona(p).permiso(PermisoUsuario.Permiso.valueOf(code)).build()));auditoria.registrar(operadorId,"MODIFICAR","EMPLEADO",p.getId(),"Ficha y permisos actualizados");return dto(p);}@Transactional(readOnly=true)public boolean tiene(Long personaId,PermisoUsuario.Permiso permiso){return permisos(personaId).contains(permiso);}@Transactional(readOnly=true)public Set<PermisoUsuario.Permiso> permisos(Long personaId){return personas.findById(personaId).map(p->{if(p.getRol()==Persona.Rol.SUPER_ADMIN||p.getRol()==Persona.Rol.ADMIN)return EnumSet.allOf(PermisoUsuario.Permiso.class);return permisos.findByPersonaId(personaId).stream().map(PermisoUsuario::getPermiso).collect(java.util.stream.Collectors.toCollection(()->EnumSet.noneOf(PermisoUsuario.Permiso.class)));}).orElseGet(()->EnumSet.noneOf(PermisoUsuario.Permiso.class));}private EmpleadoDTO dto(Persona p){PerfilEmpleado e=perfiles.findByPersonaId(p.getId()).orElse(null);Set<String> ps=permisos.findByPersonaId(p.getId()).stream().map(x->x.getPermiso().name()).collect(java.util.stream.Collectors.toSet());return new EmpleadoDTO(p.getId(),p.getNombre(),p.getApellido(),p.getEmail(),p.getRol().name(),p.isActivo(),e==null?null:e.getLegajo(),e==null?null:e.getPuesto(),e==null?null:e.getFechaContratacion(),e==null?null:e.getSueldo(),e==null?null:e.getTelefonoEmergencia(),e==null?null:e.getObservaciones(),ps);}private String clean(String s){return s==null||s.isBlank()?null:s.trim();}}
